PREFIX : <http://ambrosia.example.org/construction#>
PREFIX p: <http://ambrosia.example.org/construction/prop#>
SELECT ?iid ?dt ?res ?emp WHERE { ?si a :Inspection_Types ; p:inspectionID ?iid ; p:date ?dt ; p:result ?res ; p:inspectorEmployeeID ?emp . ?e a :Employees ; p:supervisorID ?sup ; p:role ?role . FILTER(STR(?emp)=STR(?sup)) FILTER(STR(?role)='Site Supervisor') }

